  <div class="spn" id="spn"><div class="spn-ring"></div></div>
</div></div>
<script>
(function(){
var K={N:'up6n',U:'up6u',P:'up6p',SC:'up6sc',CART:'up6cart',BP:'up6bp'};
var S={},NAV={scr:'home',cid:null,scTab:'feed',shCat:'All',shItem:null,shView:'list',cmPost:null,replyTo:null,shQty:1,bkTab:'main'},US={wl:'',wh:''};

function g(id){return document.getElementById(id)}
function e(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;')}
function ts(t){try{if(t==null)return'';var s=String(t).trim();var rp=s.match(/^(\d{1,2}):(\d{2})$/);if(rp)return('0'+rp[1]).slice(-2)+':'+rp[2];var d=new Date(t);return isNaN(d)?'':('0'+d.getHours()).slice(-2)+':'+('0'+d.getMinutes()).slice(-2)}catch(_){return''}}
function fmtDate(t){try{var d=new Date(t),n=new Date(),diff=Math.floor((n-d)/60000);if(diff<1)return'Just now';if(diff<60)return diff+'m ago';if(diff<1440)return Math.floor(diff/60)+'h ago';return d.toLocaleDateString(undefined,{month:'short',day:'numeric'})}catch(_){return''}}
function ld(k,d){try{var r=localStorage.getItem(k);return r?JSON.parse(r):d}catch(_){return d}}
function sv(k,v){try{localStorage.setItem(k,JSON.stringify(v))}catch(_){}}
function fc(id){return(S.contacts||[]).find(function(c){return c.id===id})||null}
function fmtAmt(n,cur){var c=cur||((S.bank&&S.bank.currency)||'');return c+Number(n).toLocaleString()}

function loadS(){
  var raw='';
  try{var el=g('__d');if(el)raw=(el.textContent||'').trim()}catch(_){}
  raw=raw.replace(/<\/?PHONE[^>]*>/gi,'').trim();
  if(raw.length>2){try{return JSON.parse(raw)}catch(_){}
  try{var ta=document.createElement('textarea');ta.innerHTML=raw;return JSON.parse(ta.value)}catch(_){}}
  return null;
}
function getPend(cid){return(ld(K.P,{})||{})[cid]||[]}
function setPend(cid,a){var p=ld(K.P,{})||{};p[cid]=a;sv(K.P,p)}
function getSocPend(){return ld(K.SC,[])||[]}
function setSocPend(a){sv(K.SC,a)}
function getCart(){return ld(K.CART,{})||{}}
function setCart(c){sv(K.CART,c)}
function getBkPend(){return ld(K.BP,[])||[]}
function setBkPend(a){sv(K.BP,a)}

function out(txt){
  var wins=[window.parent,window.top,window];
  for(var i=0;i<wins.length;i++){
    try{
      var w=wins[i];if(!w||!w.document)continue;
      var ta=w.document.getElementById('send_textarea')||w.document.querySelector('textarea');
      if(!ta)continue;
      ta.focus();
      var setter=Object.getOwnPropertyDescriptor(w.HTMLTextAreaElement.prototype,'value');
      if(setter&&setter.set)setter.set.call(ta,txt);else ta.value=txt;
      ta.dispatchEvent(new Event('input',{bubbles:true,cancelable:true}));
      ta.dispatchEvent(new Event('change',{bubbles:true,cancelable:true}));
      setTimeout(function(){
        var sb=w.document.getElementById('send_but')||w.document.querySelector('#sendButton,button[id*="send_but"]');
        if(sb){sb.click();return}
        ta.dispatchEvent(new KeyboardEvent('keydown',{key:'Enter',keyCode:13,bubbles:true}));
      },300);return;
    }catch(_){}
  }
  try{navigator.clipboard.writeText(txt).then(function(){alert('Copied!')})}catch(_){prompt('Copy:',txt)}
}
function showSpin(){var s=g('spn');if(s)s.classList.add('on')}
function hideSpin(){var s=g('spn');if(s)s.classList.remove('on')}

function setBg(){
  var el=g('bg');if(!el)return;
  var url=(US.wh||US.wl);
  if(url)el.style.cssText='position:absolute;inset:0;background:url("'+url+'") center/cover no-repeat';
  else el.style.cssText='position:absolute;inset:0;background:linear-gradient(160deg,#0f0c29,#302b63 55%,#24243e)';
}

function r(){
  setBg();
  var sbt=g('sbt');if(sbt)sbt.textContent=S.time||'--:--';
  var v=g('view');if(!v)return;v.innerHTML='';
  var s=NAV.scr;
  if(s==='home')rHome(v);
  else if(s==='chats')rChats(v);
  else if(s==='chat')rThread(v);
  else if(s==='social')rSocial(v);
  else if(s==='social_cm')rComments(v);
  else if(s==='shop')rShop(v);
  else if(s==='shop_item')rShopItem(v);
  else if(s==='shop_cart')rCart(v);
  else if(s==='bank')rBank(v);
  else if(s==='bank_transfer')rTransfer(v);
  else if(s==='settings')rSettings(v);
  else rHome(v);
}

function rHome(v){
  var ums=0,chats=S.chats||{};
  Object.keys(chats).forEach(function(k){(chats[k]||[]).forEach(function(m){if(m.from!=='self')ums++})});
  var carts=Object.keys(getCart()).length;
  var bkp=getBkPend().length;
  var d=document.createElement('div');d.className='scr hm';
  d.innerHTML='<div class="hm-clk">'+e(S.time||'--:--')+'</div>'
    +'<div class="hm-dt">'+e(S.date||'')+'</div>'
    +'<div class="hm-grid">'
    +'<div class="ap" onclick="P.go(\'chats\')"><div class="ap-ic ic-ch">'+(ums?'<div class="ap-bd">'+ums+'</div>':'')+'💬</div><div class="ap-lb">Messages</div></div>'
    +'<div class="ap" onclick="P.go(\'social\')"><div class="ap-ic ic-sc">📱</div><div class="ap-lb">Social</div></div>'
    +'<div class="ap" onclick="P.go(\'shop\')"><div class="ap-ic ic-sh" style="position:relative">'+(carts?'<div class="ap-bd">'+carts+'</div>':'')+'🛍</div><div class="ap-lb">Shop</div></div>'
    +'<div class="ap" onclick="P.go(\'bank\')"><div class="ap-ic ic-bk" style="position:relative">'+(bkp?'<div class="ap-bd">'+bkp+'</div>':'')+'🏦</div><div class="ap-lb">Bank</div></div>'
    +'<div class="ap" onclick="P.go(\'settings\')"><div class="ap-ic ic-set">⚙</div><div class="ap-lb">Settings</div></div>'
    +'</div>'
    +'<div class="hm-bar" onclick="P.go(\'home\')"></div>';
  v.appendChild(d);
}

function rSettings(v){
  var d=document.createElement('div');d.className='scr app';
  d.innerHTML='<div class="nav"><button class="nav-bk" onclick="P.home()">‹ Home</button><div class="nav-ti">Settings</div><div style="min-width:44px"></div></div>'
    +'<div class="ab" style="padding-bottom:14px">'
    +'<div class="sg">Profile</div><div class="sl">'
    +'<div class="sr"><div class="sr-l">Name</div><input class="si" id="s_nm" value="'+e((S.user&&S.user.name)||'')+'" placeholder="Your name"></div>'
    +'<div class="sr"><div class="sr-l"></div><button class="sb2" onclick="P.saveProfile()">Save</button></div>'
    +'</div>'
    +'<div class="sg">Wallpaper</div><div class="sl">'
    +'<div class="sr"><div class="sr-l">Image URL</div><input class="si" id="s_wp" value="'+e(US.wh||US.wl)+'" placeholder="https://..."></div>'
    +'<div class="sr"><div class="sr-l"></div><button class="sb2" onclick="P.applyWp()">Apply</button></div>'
    +'</div></div>';
  v.appendChild(d);
}

/* ══ CHAT ══ */
function rChats(v){
  var cs=S.contacts||[],ch=S.chats||{};
  var d=document.createElement('div');d.className='scr app';
  var body='';
  if(!cs.length)body='<div class="empty">No conversations yet.</div>';
  else cs.forEach(function(c){
    var msgs=ch[c.id]||[],lm=msgs.length?msgs[msgs.length-1]:null;
    var urd=msgs.filter(function(m){return m.from!=='self'}).length;
    body+='<div class="cr" onclick="P.openChat(\''+e(c.id)+'\')">'
      +'<div class="cav" style="background:'+e(c.color||'#5e72e4')+'">'+e((c.name||'?').charAt(0))+'</div>'
      +'<div class="ci2"><div class="ch2"><div class="cn2">'+e(c.name)+(c.type==='group'?' 👥':'')+'</div>'
      +'<div class="ct2">'+(lm?ts(lm.ts):'')+'</div></div>'
      +'<div class="cp2">'+e(lm?(lm.text||'').slice(0,40):'Tap to message')+'</div></div>'
      +(urd?'<div class="cub">'+urd+'</div>':'')+'</div>';
  });
  d.innerHTML='<div class="nav"><button class="nav-bk" onclick="P.home()">‹ Home</button><div class="nav-ti">Messages</div><button class="nav-ac" onclick="P.newContact()">+</button></div>'
    +'<div class="ab">'+body+'</div>';
  v.appendChild(d);
}

function rThread(v){
  var cid=NAV.cid,c=fc(cid);
  if(!c){NAV.scr='chats';r();return}
  var msgs=(S.chats&&S.chats[cid])||[],pd=getPend(cid);
  var d=document.createElement('div');d.className='scr app';
  var nav='<div class="nav"><button class="nav-bk" onclick="P.backChat()">‹</button>'
    +'<div class="nav-ti" style="display:flex;align-items:center;gap:6px;justify-content:center">'
    +'<div style="width:24px;height:24px;border-radius:50%;background:'+e(c.color||'#5e72e4')+';flex-shrink:0"></div>'
    +e(c.name)+'</div><div style="min-width:44px"></div></div>';
  var bb='<div class="tbdy" id="tb">';
  if(!msgs.length&&!pd.length)bb+='<div class="empty" style="padding:24px 0">Start of conversation</div>';
  msgs.forEach(function(m){bb+=mkBub(m,c,false)});
  pd.forEach(function(m){bb+=mkBub({from:'self',text:m.text,ts:m.ts},c,true)});
  bb+='</div>';
  var pbar=pd.length?'<div class="pbar"><div class="pbar-t">'+pd.length+' pending</div><div class="pbar-bs"><button class="xbtn xc" onclick="P.cancelChat()">Cancel</button><button class="xbtn xs" onclick="P.sendChat()">Send</button></div></div>':'';
  d.innerHTML=nav+'<div class="ab" id="thr">'+bb+'</div>'+pbar
    +'<div class="af"><div class="ibar"><textarea class="mta" id="mi" placeholder="Message" rows="1"></textarea><button class="sbtn" onclick="P.qChat()">↑</button></div></div>';
  v.appendChild(d);
  setTimeout(function(){
    var ta=g('mi');
    if(ta){ta.oninput=function(){this.style.height='auto';this.style.height=Math.min(this.scrollHeight,80)+'px'};
    ta.onkeydown=function(ev){if(ev.key==='Enter'&&!ev.shiftKey){ev.preventDefault();P.qChat()}}}
    var t=g('thr');if(t)t.scrollTop=t.scrollHeight;
  },20);
}

function mkBub(m,c,pe){
  var cls='bbl '+(m.from==='self'?(pe?'pe':'ou'):'in');
  var h='<div class="'+cls+'">';
  if(c.type==='group'&&m.from!=='self'){var mc=fc(m.from);h+='<div class="bgf" style="color:'+e((mc&&mc.color)||'#aaa')+'">'+e(mc?mc.name:(m.from_name||m.from))+'</div>'}
  if(m.text)h+=e(m.text).replace(/\n/g,'<br>');
  if(m.ts)h+='<div class="bts">'+ts(m.ts)+'</div>';
  return h+'</div>';
}

/* ══ SOCIAL ══ */
function rSocial(v){
  var tab=NAV.scTab||'feed';
  var posts=S.posts||[];
  var d=document.createElement('div');d.className='scr app';
  var spd=getSocPend();
  var body='';
  if(tab==='feed'){
    if(!posts.length)body='<div class="empty">No posts yet.</div>';
    else posts.forEach(function(p,i){body+=mkPost(p,i,spd)});
  } else {
    var un=(S.user&&S.user.name)||'You';
    var ui=(un.charAt(0)||'Y').toUpperCase();
    body='<div class="compose"><div class="compose-row"><div class="compose-av">'+ui+'</div>'
      +'<div class="compose-in"><textarea class="compose-ta" id="compTA" placeholder="What\'s on your mind?" oninput="P.composeInput(this)" maxlength="280"></textarea>'
      +'<div class="compose-foot"><div class="compose-lim" id="compLim">280</div>'
      +'<button class="compose-post" id="compBtn" disabled onclick="P.postCompose()">Post</button></div>'
      +'</div></div></div>'
      +(spd.length?'<div class="cm-pending" style="border-bottom:1px solid rgba(255,255,255,.05)">'
        +'<div class="cm-pending-t">'+spd.length+' pending action'+(spd.length>1?'s':'')+'</div>'
        +'<div class="pbar-bs"><button class="xbtn xc" style="padding:4px 10px" onclick="P.cancelSocPend()">Cancel</button>'
        +'<button class="xbtn xs" style="padding:4px 10px" onclick="P.sendSocPend()">Send All</button></div></div>':'');
  }
  d.innerHTML='<div class="nav"><button class="nav-bk" onclick="P.home()">‹ Home</button><div class="nav-ti">Social</div>'
    +(spd.length&&tab==='feed'?'<button class="nav-ac" onclick="P.sendSocPend()">Send('+spd.length+')</button>':'<div style="min-width:44px"></div>')
    +'</div>'
    +'<div class="sc-tabs"><div class="sc-tab '+(tab==='feed'?'on':'')+'" onclick="P.socTab(\'feed\')">Feed</div>'
    +'<div class="sc-tab '+(tab==='compose'?'on':'')+'" onclick="P.socTab(\'compose\')">Post</div></div>'
    +'<div class="ab">'+body+'</div>';
  v.appendChild(d);
}

function mkPost(p,i,spd){
  var uid=p.id||String(i);
  var isLiked=!!(p.liked||spd.find(function(x){return x.type==='like'&&x.post_id===uid}));
  var likeCount=(p.likes||0)+(spd.filter(function(x){return x.type==='like'&&x.post_id===uid}).length);
  var cmCount=(p.comments||[]).length+(spd.filter(function(x){return(x.type==='comment'||x.type==='reply')&&x.post_id===uid}).length);
  var av=p.author?(p.author.charAt(0)||'?').toUpperCase():'?';
  var clr=p.color||'#5e72e4';
  var h='<div class="post">'
    +'<div class="post-head"><div class="post-av" style="background:'+e(clr)+'">'+av+'</div>'
    +'<div class="post-info"><div class="post-nm">'+e(p.author||'Anonymous')+'</div>'
    +'<div class="post-ts">'+e(fmtDate(p.ts)||p.date||'')+'</div></div></div>'
    +(p.text?'<div class="post-txt">'+e(p.text).replace(/\n/g,'<br>')+'</div>':'')
    +(p.image?'<div class="post-img"><img src="'+e(p.image)+'" onerror="this.parentNode.innerHTML=\'🖼\'"></div>':'');
  h+='<div class="post-acts">'
    +'<div class="pa'+(isLiked?' liked':'')+'" onclick="P.likePost(\''+e(uid)+'\')"><span class="pa-ic">'+(isLiked?'❤️':'🤍')+'</span>'+likeCount+'</div>'
    +'<div class="pa" onclick="P.openComments(\''+e(uid)+'\')"><span class="pa-ic">💬</span>'+cmCount+'</div>'
    +'<div class="pa" onclick="P.sharePost(\''+e(uid)+'\')"><span class="pa-ic">↗</span>Share</div>'
    +'</div></div>';
  return h;
}

function rComments(v){
  var pid=NAV.cmPost;
  var posts=S.posts||[];
  var post=posts.find(function(p,i){return (p.id||String(i))===pid})||posts[parseInt(pid,10)]||null;
  if(!post){NAV.scr='social';r();return}
  var spd=getSocPend();
  var uid=post.id||String(posts.indexOf(post));
  var allComments=(post.comments||[]).slice();
  spd.forEach(function(x){if((x.type==='comment'||x.type==='reply')&&x.post_id===uid)allComments.push({author:x.author||((S.user&&S.user.name)||'You'),text:x.text,pending:true,reply_to:x.reply_to})});
  var d=document.createElement('div');d.className='scr';d.style.cssText='position:absolute;inset:0;display:flex;flex-direction:column;background:#111';
  var clst='<div class="cm-list"><div style="padding:10px 13px 8px;border-bottom:1px solid rgba(255,255,255,.06)">'
    +'<div style="font-size:13px;color:rgba(255,255,255,.7);line-height:1.5;font-style:italic">'+e((post.text||'').slice(0,80))+(post.text&&post.text.length>80?'…':'')+'</div></div>';
  if(!allComments.length)clst+='<div class="empty">No comments yet.</div>';
  allComments.forEach(function(cm,ci){
    var cid2='c'+ci;
    var av=(cm.author||'?').charAt(0).toUpperCase();
    var isLiked=!!(cm.liked||spd.find(function(x){return x.type==='like_comment'&&x.comment_id===cid2&&x.post_id===uid}));
    clst+='<div class="cm"><div class="cm-av" style="background:'+e(cm.color||'#636366')+'">'+av+'</div>'
      +'<div class="cm-body">'+(cm.reply_to?'<div style="font-size:10px;color:#0a84ff;margin-bottom:2px">↩ '+e(cm.reply_to)+'</div>':'')
      +'<div class="cm-nm">'+e(cm.author||'Anonymous')+(cm.pending?'<span style="font-size:9px;color:#ff9f0a;margin-left:5px">● pending</span>':'')+'</div>'
      +'<div class="cm-txt">'+e(cm.text||'')+'</div>'
      +'<div class="cm-acts"><div class="cm-act'+(isLiked?' liked':'')+'" onclick="P.likeComment(\''+e(uid)+'\',\''+cid2+'\')">'+( isLiked?'❤':'♡')+' Like</div>'
      +'<div class="cm-act" onclick="P.replyComment(\''+e(uid)+'\',\''+e(cm.author||'')+'\')">Reply</div>'
      +'</div></div></div>';
  });
  clst+='</div>';
  var pendBar=spd.filter(function(x){return x.post_id===uid}).length;
  var pbarHtml=pendBar?'<div class="cm-pending"><div class="cm-pending-t">'+pendBar+' pending</div>'
    +'<div class="pbar-bs"><button class="xbtn xc" style="padding:4px 10px;font-size:10px" onclick="P.cancelSocPend()">Cancel</button>'
    +'<button class="xbtn xs" style="padding:4px 10px;font-size:10px" onclick="P.sendSocPend()">Send All</button></div></div>':'';
  var ph=NAV.replyTo?'Reply to '+NAV.replyTo+'…':'Add a comment…';
  d.innerHTML='<div class="nav"><button class="nav-bk" onclick="P.backComments()">‹</button><div class="nav-ti">Comments</div><div style="min-width:44px"></div></div>'
    +clst+pbarHtml
    +'<div class="af"><div class="ibar"><textarea class="mta" id="cmIn" placeholder="'+e(ph)+'" rows="1"></textarea>'
    +'<button class="sbtn" onclick="P.qComment(\''+e(uid)+'\')">↑</button></div></div>';
  v.appendChild(d);
  setTimeout(function(){var ta=g('cmIn');if(ta){ta.oninput=function(){this.style.height='auto';this.style.height=Math.min(this.scrollHeight,80)+'px'}}},20);
}

/* ══ SHOP ══ */
function rShop(v){
  var items=S.shop_items||[],cat=NAV.shCat||'All',cats=['All'];
  items.forEach(function(it){if(it.category&&cats.indexOf(it.category)<0)cats.push(it.category)});
  var filtered=cat==='All'?items:items.filter(function(it){return it.category===cat});
  var cartCount=Object.keys(getCart()).length;
  var catH='<div class="sh-cats">';
  cats.forEach(function(c){catH+='<div class="sh-cat'+(c===cat?' on':'')+'" onclick="P.shCat(\''+e(c)+'\')">'+e(c)+'</div>'});
  catH+='</div>';
  var grid='<div class="sh-grid">';
  if(!filtered.length)grid+='</div><div class="empty">No items.</div>';
  else{filtered.forEach(function(it){
    var idx=items.indexOf(it);
    var thumb=it.image?'<img src="'+e(it.image)+'" onerror="this.parentNode.innerHTML=\''+e(it.emoji||'📦')+'\'">':(it.emoji||'📦');
    grid+='<div class="sh-item" onclick="P.openItem('+idx+')">'
      +'<div class="sh-thumb">'+thumb+'</div>'
      +'<div class="sh-info"><div class="sh-nm">'+e(it.name||'Item')+'</div>'
      +'<div class="sh-pr">'+e(it.price||'')+'</div>'
      +(it.stock!=null?'<div class="sh-sub">'+(it.stock>0?'In stock':'Out of stock')+'</div>':'')
      +'</div></div>';
  });grid+='</div>';}
  var d=document.createElement('div');d.className='scr app';
  d.innerHTML='<div class="nav"><button class="nav-bk" onclick="P.home()">‹ Home</button><div class="nav-ti">Shop</div>'
    +'<button class="nav-ac" onclick="P.go(\'shop_cart\')" style="position:relative">🛒'+(cartCount?'<span class="cart-badge">'+cartCount+'</span>':'')+'</button></div>'
    +'<div class="ab">'+catH+grid+'</div>';
  v.appendChild(d);
}

function rShopItem(v){
  var items=S.shop_items||[],it=items[NAV.shItem];
  if(!it){NAV.scr='shop';r();return}
  var cart=getCart(),qty=NAV.shQty||1,inCart=cart[String(NAV.shItem)];
  var thumb=it.image?'<img src="'+e(it.image)+'" onerror="this.parentNode.innerHTML=\''+e(it.emoji||'📦')+'\'" style="width:100%;height:100%;object-fit:cover;border-radius:14px">':(it.emoji||'📦');
  var d=document.createElement('div');d.className='scr app';
  d.innerHTML='<div class="nav"><button class="nav-bk" onclick="P.backShop()">‹ Shop</button><div class="nav-ti">Item</div>'
    +'<button class="nav-ac" onclick="P.go(\'shop_cart\')" style="position:relative">🛒'+(Object.keys(cart).length?'<span class="cart-badge">'+Object.keys(cart).length+'</span>':'')+'</button></div>'
    +'<div class="ab"><div class="sh-det"><div class="sh-det-thumb">'+thumb+'</div>'
    +'<div class="sh-det-cat">'+e(it.category||'')+'</div>'
    +'<div class="sh-det-nm">'+e(it.name||'')+'</div>'
    +'<div class="sh-det-pr">'+e(it.price||'')+'</div>'
    +(it.description?'<div class="sh-det-desc">'+e(it.description)+'</div>':'')
    +'<div class="qty-row"><div class="qty-lbl">Quantity</div><div class="qty-ctrl">'
    +'<button class="qty-btn" onclick="P.qtyMinus()">−</button><div class="qty-n" id="qtyN">'+qty+'</div><button class="qty-btn" onclick="P.qtyPlus()">+</button>'
    +'</div></div>'+(it.stock===0?'<div style="text-align:center;color:#ff3b30;font-size:13px;font-weight:600;padding:10px 0;margin-bottom:10px">Out of Stock</div>':'')
    +'<button class="add-cart" onclick="P.addToCart()">'+(inCart?'Update Cart':'Add to Cart')+'</button></div></div>';
  v.appendChild(d);
}

function rCart(v){
  var cart=getCart(),items=S.shop_items||[],keys=Object.keys(cart);
  var body='',total=0;
  if(!keys.length)body='<div class="empty">Your cart is empty.</div>';
  else{
    keys.forEach(function(k){
      var it=items[parseInt(k,10)];if(!it)return;
      var qty=cart[k],prNum=parseFloat(String(it.price||0).replace(/[^0-9.]/g,''))||0;
      total+=prNum*qty;
      var thumb=it.image?'<img src="'+e(it.image)+'" onerror="this.innerHTML=\''+e(it.emoji||'📦')+'\'" style="width:100%;height:100%;object-fit:cover;border-radius:8px">':(it.emoji||'📦');
      body+='<div class="cart-item"><div class="cart-ic">'+thumb+'</div>'
        +'<div class="cart-info"><div class="cart-nm">'+e(it.name||'')+'</div><div class="cart-sub">Qty: '+qty+'</div></div>'
        +'<div class="cart-pr">'+e(it.price||'')+'</div>'
        +'<button class="cart-del" onclick="P.removeCart(\''+k+'\')">✕</button></div>';
    });
    body+='<div class="cart-total"><div class="cart-total-l">Total</div><div class="cart-total-r">'+(total?total.toFixed(2):'—')+'</div></div>';
  }
  var d=document.createElement('div');d.className='scr app';
  d.innerHTML='<div class="nav"><button class="nav-bk" onclick="P.backShop()">‹ Shop</button><div class="nav-ti">Cart ('+keys.length+')</div><div style="min-width:44px"></div></div>'
    +'<div class="ab">'+body+'</div>'
    +'<div class="af" style="padding:10px 0 14px"><button class="order-btn" onclick="P.placeOrder()" '+(keys.length?'':'disabled')+'>Place Order</button></div>';
  v.appendChild(d);
}

/* ══ BANK ══ */
function rBank(v){
  var bk=S.bank||{};
  var txs=(bk.transactions||[]).slice().reverse();
  var bkp=getBkPend();
  var cur=bk.currency||'';
  var bal=bk.balance!=null?fmtAmt(bk.balance,cur):'—';
  var acctName=bk.account_name||(S.user&&S.user.name)||'Account';
  var acctNum=bk.account_number||'';

  // Pending tx show at top
  var txBody='';
  bkp.forEach(function(p){
    txBody+='<div class="tx"><div class="tx-ic pd">⏳</div>'
      +'<div class="tx-info"><div class="tx-nm">'+e(p.to||'Transfer')+'<span class="tx-pd-tag">pending</span></div>'
      +'<div class="tx-dt">'+e(p.note||'')+'</div></div>'
      +'<div class="tx-am pd">−'+fmtAmt(p.amount,cur)+'</div></div>';
  });

  if(!txs.length&&!bkp.length)txBody+='<div class="empty">No transactions yet.</div>';
  txs.forEach(function(tx){
    var isCredit=tx.type==='credit';
    var icon=isCredit?'💚':'🔴';
    txBody+='<div class="tx"><div class="tx-ic '+(isCredit?'cr':'db')+'">'+icon+'</div>'
      +'<div class="tx-info"><div class="tx-nm">'+e(tx.description||tx.to||tx.from||'Transaction')+'</div>'
      +'<div class="tx-dt">'+(isCredit&&tx.from?'From: '+e(tx.from):'')+((!isCredit)&&tx.to?'To: '+e(tx.to):'')+(tx.ts?' · '+fmtDate(tx.ts):'')+'</div></div>'
      +'<div class="tx-am '+(isCredit?'cr':'db')+'">'+(isCredit?'+':'−')+fmtAmt(tx.amount,cur)+'</div></div>';
  });

  var d=document.createElement('div');d.className='scr app';
  var pbarHtml=bkp.length?'<div class="tx-pend-bar"><div class="tx-pend-t">'+bkp.length+' pending transfer'+(bkp.length>1?'s':'')+'</div>'
    +'<div class="pbar-bs"><button class="xbtn xc" style="padding:4px 10px;font-size:11px" onclick="P.cancelBkPend()">Cancel</button>'
    +'<button class="xbtn xs" style="padding:4px 10px;font-size:11px" onclick="P.sendBkPend()">Confirm</button></div></div>':'';
  d.innerHTML='<div class="nav"><button class="nav-bk" onclick="P.home()">‹ Home</button><div class="nav-ti">Bank</div><div style="min-width:44px"></div></div>'
    +'<div class="ab">'
    +'<div class="bk-card">'
    +'<div class="bk-label">Available Balance</div>'
    +'<div class="bk-bal">'+e(bal)+'</div>'
    +'<div class="bk-row"><div class="bk-acct">'+e(acctNum)+'</div><div class="bk-name">'+e(acctName)+'</div></div>'
    +'</div>'
    +'<div class="bk-acts">'
    +'<div class="bk-act" onclick="P.go(\'bank_transfer\')"><div class="bk-act-ic">↑</div><div class="bk-act-lb">Transfer</div></div>'
    +'</div>'
    +'<div class="sg">Transactions</div>'
    +txBody+'</div>'+pbarHtml;
  v.appendChild(d);
}

function rTransfer(v){
  var bk=S.bank||{};
  var cur=bk.currency||'';
  var bal=bk.balance!=null?fmtAmt(bk.balance,cur):'—';
  var contacts=S.contacts||[];
  var contactPills='';
  contacts.forEach(function(c){
    contactPills+='<div class="tf-contact" id="tfc_'+e(c.id)+'" onclick="P.tfPick(\''+e(c.id)+'\',\''+e(c.name)+'\')">'+e(c.name)+'</div>';
  });
  var d=document.createElement('div');d.className='scr app';
  d.innerHTML='<div class="nav"><button class="nav-bk" onclick="P.go(\'bank\')">‹ Bank</button><div class="nav-ti">Transfer</div><div style="min-width:44px"></div></div>'
    +'<div class="ab"><div class="tf-form">'
    +'<div style="text-align:center;padding:6px 0 12px;font-size:12px;color:#636366">Balance: '+e(bal)+'</div>'
    +(contactPills?'<div class="tf-label">Quick Select</div><div class="tf-contacts" id="tfContacts">'+contactPills+'</div>':'')
    +'<div class="tf-group"><div class="tf-label">To</div><input class="tf-input" id="tfTo" placeholder="Recipient name or account" oninput="P.tfValidate()"></div>'
    +'<div class="tf-group"><div class="tf-label">Amount</div><input class="tf-input" id="tfAmt" type="number" placeholder="0" min="1" oninput="P.tfValidate()"></div>'
    +'<div class="tf-group"><div class="tf-label">Note (optional)</div><input class="tf-input" id="tfNote" placeholder="What\'s this for?"></div>'
    +'<button class="tf-send" id="tfSend" disabled onclick="P.qTransfer()">Add to Queue</button>'
    +'</div></div>';
  v.appendChild(d);
  setTimeout(function(){P.tfValidate()},10);
}

/* ── ACTIONS ── */
window.P={
  home:function(){NAV.scr='home';NAV.cid=null;sv(K.N,NAV);r()},
  go:function(scr){NAV.scr=scr;sv(K.N,NAV);r()},
  saveProfile:function(){var nm=g('s_nm');if(!nm)return;if(!S.user)S.user={};S.user.name=nm.value.trim();sv(K.N,NAV);r()},
  applyWp:function(){var wp=g('s_wp');if(!wp)return;US.wh=US.wl=wp.value.trim();sv(K.U,US);r()},

  /* CHAT */
  openChat:function(id){NAV.scr='chat';NAV.cid=id;sv(K.N,NAV);r()},
  backChat:function(){NAV.scr='chats';NAV.cid=null;sv(K.N,NAV);r()},
  newContact:function(){
    var nm=prompt('Contact name:');if(!nm||!nm.trim())return;
    var col=prompt('Color (hex):','#5e72e4')||'#5e72e4';
    var id=nm.trim().toLowerCase().replace(/\s+/g,'_').replace(/[^a-z0-9_]/g,'').slice(0,24)||'c'+Date.now().toString(36);
    if(!S.contacts)S.contacts=[];
    if(!S.contacts.find(function(c){return c.id===id}))S.contacts.push({id:id,name:nm.trim(),color:col,type:'person'});
    out('[ Contact Added: '+nm.trim()+' ]');r();
  },
  qChat:function(){
    var ta=g('mi');if(!ta)return;var t=(ta.value||'').trim();if(!t)return;
    var cid=NAV.cid;if(!cid)return;
    var pd=getPend(cid);pd.push({text:t,ts:(S.time||'')});
    setPend(cid,pd);ta.value='';ta.style.height='auto';r();
  },
  cancelChat:function(){var cid=NAV.cid;if(cid)setPend(cid,[]);r()},
  sendChat:function(){
    var cid=NAV.cid;if(!cid)return;var pd=getPend(cid);if(!pd.length)return;
    var c=fc(cid),cn=c?c.name:cid,line='─────────────────────────────────';
    var lines=['[ Chat: '+cn+(c&&c.type==='group'?' (Group)':'')+' ]',line];
    pd.forEach(function(m,i){lines.push((i+1)+'. '+m.text)});
    lines.push(line);lines.push((S.date||'')+'  '+(S.time||''));
    setPend(cid,[]);showSpin();setTimeout(function(){hideSpin();out(lines.join('\n'))},400);
  },

  /* SOCIAL */
  socTab:function(t){NAV.scTab=t;sv(K.N,NAV);r()},
  composeInput:function(el){var lim=g('compLim'),btn=g('compBtn');if(lim)lim.textContent=280-((el.value||'').length);if(btn)btn.disabled=!(el.value||'').trim()},
  postCompose:function(){
    var ta=g('compTA');if(!ta)return;var t=(ta.value||'').trim();if(!t)return;
    var un=(S.user&&S.user.name)||'You',spd=getSocPend();
    spd.push({type:'post',author:un,text:t,ts:new Date().toISOString()});
    setSocPend(spd);ta.value='';NAV.scTab='feed';sv(K.N,NAV);r();
  },
  likePost:function(pid){var spd=getSocPend();var ex=spd.findIndex(function(x){return x.type==='like'&&x.post_id===pid});if(ex>=0)spd.splice(ex,1);else spd.push({type:'like',post_id:pid,ts:new Date().toISOString()});setSocPend(spd);r()},
  openComments:function(pid){NAV.scr='social_cm';NAV.cmPost=pid;NAV.replyTo=null;sv(K.N,NAV);r()},
  backComments:function(){NAV.scr='social';NAV.cmPost=null;NAV.replyTo=null;sv(K.N,NAV);r()},
  qComment:function(pid){
    var ta=g('cmIn');if(!ta)return;var t=(ta.value||'').trim();if(!t)return;
    var un=(S.user&&S.user.name)||'You',spd=getSocPend();
    spd.push({type:NAV.replyTo?'reply':'comment',post_id:pid,author:un,text:t,reply_to:NAV.replyTo||null,ts:new Date().toISOString()});
    setSocPend(spd);NAV.replyTo=null;ta.value='';ta.style.height='auto';r();
  },
  likeComment:function(pid,cid){var spd=getSocPend();var ex=spd.findIndex(function(x){return x.type==='like_comment'&&x.post_id===pid&&x.comment_id===cid});if(ex>=0)spd.splice(ex,1);else spd.push({type:'like_comment',post_id:pid,comment_id:cid,ts:new Date().toISOString()});setSocPend(spd);r()},
  replyComment:function(pid,author){NAV.replyTo=author;r()},
  sharePost:function(pid){var spd=getSocPend();spd.push({type:'share',post_id:pid,ts:new Date().toISOString()});setSocPend(spd);r()},
  cancelSocPend:function(){setSocPend([]);r()},
  sendSocPend:function(){
    var spd=getSocPend();if(!spd.length)return;
    var line='─────────────────────────────────',lines=['[ Social Actions ]',line],posts=S.posts||[];
    spd.forEach(function(x,i){
      var pInfo='';if(x.post_id!=null){var p=posts.find(function(pp,pi){return (pp.id||String(pi))===String(x.post_id)});if(p)pInfo=' — "'+( p.text||'').slice(0,28)+(p.text&&p.text.length>28?'…':'')+'"'}
      if(x.type==='post')lines.push((i+1)+'. [NEW POST] '+x.text);
      else if(x.type==='like')lines.push((i+1)+'. [LIKE] Post'+pInfo);
      else if(x.type==='comment')lines.push((i+1)+'. [COMMENT on Post'+pInfo+'] '+x.text);
      else if(x.type==='reply')lines.push((i+1)+'. [REPLY to '+x.reply_to+' on Post'+pInfo+'] '+x.text);
      else if(x.type==='like_comment')lines.push((i+1)+'. [LIKE COMMENT] '+x.comment_id+' on Post'+pInfo);
      else if(x.type==='share')lines.push((i+1)+'. [SHARE] Post'+pInfo);
    });
    lines.push(line);lines.push((S.date||'')+'  '+(S.time||''));
    setSocPend([]);showSpin();setTimeout(function(){hideSpin();out(lines.join('\n'))},400);
  },

  /* SHOP */
  shCat:function(c){NAV.shCat=c;sv(K.N,NAV);r()},
  openItem:function(i){NAV.scr='shop_item';NAV.shItem=i;NAV.shQty=1;sv(K.N,NAV);r()},
  backShop:function(){NAV.scr='shop';sv(K.N,NAV);r()},
  qtyMinus:function(){NAV.shQty=Math.max(1,(NAV.shQty||1)-1);var el=g('qtyN');if(el)el.textContent=NAV.shQty},
  qtyPlus:function(){var it=(S.shop_items||[])[NAV.shItem];var max=it&&it.stock!=null?it.stock:99;NAV.shQty=Math.min(max,(NAV.shQty||1)+1);var el=g('qtyN');if(el)el.textContent=NAV.shQty},
  addToCart:function(){var cart=getCart();cart[String(NAV.shItem)]=NAV.shQty||1;setCart(cart);NAV.scr='shop';sv(K.N,NAV);r()},
  removeCart:function(k){var cart=getCart();delete cart[k];setCart(cart);r()},
  placeOrder:function(){
    var cart=getCart(),items=S.shop_items||[],keys=Object.keys(cart);if(!keys.length)return;
    var line='─────────────────────────────────',lines=['[ Order Placed ]',line];var total=0;
    keys.forEach(function(k,i){var it=items[parseInt(k,10)];if(!it)return;var qty=cart[k];var prNum=parseFloat(String(it.price||0).replace(/[^0-9.]/g,''))||0;total+=prNum*qty;lines.push((i+1)+'. '+it.name+' × '+qty+' @ '+it.price)});
    if(total){lines.push(line);lines.push('Total: '+total.toFixed(2))}
    lines.push(line);lines.push((S.date||'')+'  '+(S.time||''));
    setCart({});showSpin();setTimeout(function(){hideSpin();out(lines.join('\n'))},400);
  },

  /* BANK */
  tfPick:function(id,name){
    var inp=g('tfTo');if(inp)inp.value=name;
    document.querySelectorAll('.tf-contact').forEach(function(el){el.classList.toggle('on',el.id==='tfc_'+id)});
    P.tfValidate();
  },
  tfValidate:function(){
    var to=(g('tfTo')||{}).value||'',amt=(g('tfAmt')||{}).value||'';
    var btn=g('tfSend');if(btn)btn.disabled=!(to.trim()&&parseFloat(amt)>0);
  },
  qTransfer:function(){
    var to=((g('tfTo')||{}).value||'').trim();
    var amt=parseFloat((g('tfAmt')||{}).value||0);
    var note=((g('tfNote')||{}).value||'').trim();
    if(!to||!(amt>0))return;
    var bkp=getBkPend();
    bkp.push({to:to,amount:amt,note:note,ts:new Date().toISOString()});
    setBkPend(bkp);
    // Clear inputs
    ['tfTo','tfAmt','tfNote'].forEach(function(id){var el=g(id);if(el)el.value=''});
    document.querySelectorAll('.tf-contact').forEach(function(el){el.classList.remove('on')});
    P.tfValidate();
    NAV.scr='bank';sv(K.N,NAV);r();
  },
  cancelBkPend:function(){setBkPend([]);r()},
  sendBkPend:function(){
    var bkp=getBkPend();if(!bkp.length)return;
    var cur=(S.bank&&S.bank.currency)||'';
    var line='─────────────────────────────────',lines=['[ Bank Transfer ]',line];
    var total=0;
    bkp.forEach(function(p,i){
      total+=p.amount;
      lines.push((i+1)+'. To: '+p.to+'  Amount: '+fmtAmt(p.amount,cur)+(p.note?' ('+p.note+')':''));
    });
    if(bkp.length>1){lines.push(line);lines.push('Total sent: '+fmtAmt(total,cur))}
    lines.push(line);lines.push((S.date||'')+'  '+(S.time||''));
    setBkPend([]);showSpin();setTimeout(function(){hideSpin();out(lines.join('\n'))},400);
  },
};

function init(){
  try{
    NAV=Object.assign({scr:'home',cid:null,scTab:'feed',shCat:'All',shItem:null,cmPost:null,replyTo:null,shQty:1,bkTab:'main'},ld(K.N,{})||{});
    US=Object.assign({wl:'',wh:''},ld(K.U,{})||{});
    var fresh=loadS();
    if(fresh&&typeof fresh==='object'){
      S=fresh;if(fresh.screen)NAV.scr=fresh.screen;if(fresh.active_chat)NAV.cid=fresh.active_chat;sv(K.N,NAV);
    }
    r();
  }catch(err){
    var v=g('view');
    if(v)v.innerHTML='<div style="padding:60px 16px;color:#ff453a;font-size:12px;text-align:center;line-height:1.8">Error: '+e(String(err))+'</div>';
  }
}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init);else init();
})();
</script>
